var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......저보고 아카데미 운동회에 선수로 나가라는 말씀이신가요?","JPN":"……私にアカデミー運動会の選手として出場してほしいということですか？","ENG":"... You want me to join the Academy Field Day as a player?","TWN":"……您是說讓我以選手身份參加學院運動會嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다. 고양이도 쥐를 잡을 때는 최선을 다하는 법이니까요.","JPN":"そうです。猫がネズミ狩りをする時も最善を尽くすものですから。","ENG":"That's right. A cat will use all of her strength even when hunting a rat.","TWN":"是的，因為貓在抓老鼠時也會竭盡全力。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"호랑이가 토끼를 잡을 때가 아니라요?","JPN":"獅子がウサギ狩りをする時ではなくて？","ENG":"You mean, a lioness when hunting a rabbit.","TWN":"不是老虎抓兔子嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"흥, 호랑이는 무슨.","JPN":"ふん、獅子ですって？","ENG":"Hah, nonsense.","TWN":"哼，老虎個鬼。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양에게는 도둑고양이 정도가 딱 어울립니다.","JPN":"シズカさんには野良猫程度が相応しいでしょう。","ENG":"You're a stray cat at best, Seo Yoon.","TWN":"野貓這個稱呼最適合你了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님, 혹시 입사 면접 때 일로 아직 토라져 계신 거 아니죠?","JPN":"副社長、もしかして入社面接の日のことでまだ拗ねているんですか？","ENG":"Vice President, you're not still upset because of what I said during my job interview, are you?","TWN":"副總，您不會是因為入職面試的事還在鬧脾氣吧？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무슨 소린지 모르겠네요. 전 공과 사를 아주 잘 구별하는 사람입니다.","JPN":"なんのことなのかわかりませんね。私は公私をしっかり分ける人間ですよ。","ENG":"I don't know what you're talking about. I never let my personal feelings interfere with business.","TWN":"不知道你在說什麼，我可是個公私分明的人。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"글쎄요? 저는 잘 모르겠는데......?","JPN":"そうですか？　私にはよくわかりませんが……？","ENG":"Well, I'm not so sure about that...","TWN":"是嗎？我還真不知道……？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쨌든 서윤 양이라면 경험도 부족한 풋내기 카운터들을 상대로 우승하는 건 아주 쉬운 일이겠죠.","JPN":"とにかく、シズカさんなら経験不足の青二才カウンター相手に優勝するのは簡単なことでしょう。","ENG":"Anyway, Seo Yoon, I believe it will be an easy task for you to achieve victory against those inexperienced Counters.","TWN":"總之，對於你來說，對付幾個經驗不足的新手制裁者奪得第一名應該不難吧。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 운동회에서 우승을 하고 그 <color=#ffd34c>소원구슬</color>이란 걸 가지고 와야 합니다.","JPN":"ですので運動会で優勝して、その<color=#ffd34c>願い玉</color>という物を持ってきてください。","ENG":"I want you to win the Field Day and bring back the prize called the <color=#ffd34c>Wishing Ball</color>.","TWN":"所以，你必須在運動會上奪冠，並拿回那個叫<color=#ffd34c>許願珠</color>的東西。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>어떤 소원이든 하나를 이뤄주는 구슬</color>이라......","JPN":"<color=#ffd34c>どんな願いでも叶えてくれる玉</color>だなんて……","ENG":"A <color=#ffd34c>ball that grants any single wish</color>, huh.","TWN":"<color=#ffd34c>可以實現願望的珠子</color>……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님이 그런 동화 같은 이야기를 믿으시다니. 의외로 순수한 면도 있으셨네요.","JPN":"そんなおとぎ話を信じるなんて、副社長も意外とピュアな面があったのですね。","ENG":"You believe in this fairy tale? I didn't know you were so naive.","TWN":"副總居然相信那種虛無縹緲的事情，沒想到您還有這麼單純的一面。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론 저 역시 정말로 모든 소원을 들어주는 아티팩트가 존재한다고 믿지는 않습니다.","JPN":"もちろん私も本当に願いを叶えてくれる\\nアーティファクトが存在すると信じているわけではありません。","ENG":"Of course I don't believe there is an Artifact that can grant people's wishes.","TWN":"我當然不相信真的有可以實現所有願望的人造神器。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 그런 이름이 붙을 정도라면, 적어도 강력한 힘을 가진 물건일 가능성이 크겠죠.","JPN":"しかしそのような名前が付くのであれば、\\n少なくとも何かしら強大な力を持っている物である可能性が高いです。","ENG":"But it's got to be powerful enough to be called that.","TWN":"不過既然叫了那種名字，很有可能是蘊含強大力量的東西吧。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확보한다면 회사 재정에도 큰 도움이 될 겁니다.","JPN":"確保しておけば、会社の財政にも大いに役立つでしょう。","ENG":"If we can get our hands on it, it'll greatly help us with our financial situation.","TWN":"而且對公司財政應該也是一大助力。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"후훗. 알겠어요. 저야 시키면 시키는 대로 해야죠.","JPN":"ふふ、わかりました。まあ、私に選択肢はないですけどね。","ENG":"Hah hah. Okay, I'll do as you say.","TWN":"呼呼，知道了。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 아카데미라면 조만간 미나가 편입하기로 예정된 곳 아닌가요?","JPN":"ところでアカデミーって、ミナが編入する学校ですよね？","ENG":"But Mina is supposed to transfer to the Academy soon.","TWN":"說起學院，米娜不是要去那裡插班嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 미나에게 임무를 맡기는 게 더 자연스러울 텐데요.","JPN":"それならミナに任務を任せるのが自然だと思いますが。","ENG":"Wouldn't it be more natural for her to carry out the mission?","TWN":"那直接把任務交給米娜去做應該更好吧。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양의 실력도 나쁘지는 않지만, 정신적으로는 좀 물렁한 구석이 있죠.","JPN":"ミナさんの実力も悪くありませんが、精神的な面で多少甘いところがありまして。","ENG":"Mina is good enough, but she's a bit soft mentally.","TWN":"雖然米娜的實力也不差，但性格有些柔和。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};